export const scene: DialogueEntry[] = [
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "07:28。清澄站前家庭餐廳。剛開門。店裡只有兩桌客人。", background: Background.Chapter_12_Ch12_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "澪坐在靠窗的位子。背對入口。她選這個位子是因為窗外的光從左邊過來，照在桌面上不會反光。", background: Background.Chapter_12_Ch12_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她把背包裡的東西一件一件拿出來。動作慢。像在清點。", background: Background.Chapter_12_Ch12_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "等比例照片。鏡背描圖。悠真欄位表——佐伯昨晚給的那張空白模板，她昨晚填了一半。學校說明單與預約頁列印。不連網的舊數位相機。官方筆記。私人筆記。", background: Background.Chapter_12_Ch12_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "小鏡子原件不在桌上。它鎖在她書桌最下面那層抽屜裡。", background: Background.Chapter_12_Ch12_Act1_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯原件不帶。照片和描圖夠了。今天只比文件。他昨晚說的。", background: Background.Chapter_12_Ch12_Act1_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "07:32。佐伯推門進來。深色外套。手裡一個舊電腦包。他掃了一眼店裡，看到她，走過來。沒有打招呼。拉開對面的椅子坐下。把電腦包放在腳邊。", background: Background.Chapter_12_Ch12_Act1_S0 },
    { characterId: CharacterId.SaekiTatsuya, character: "佐伯達也", dialogue: "今天只比文件。夢話、黑色海、東京，全先放旁邊。", background: Background.Chapter_12_Ch12_Act1_S0, portrait: Portrait.SaekiTatsuya_Determined },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯他第一句話就是規則。不是寒暄。不是問我昨晚睡得好不好。是規則。", background: Background.Chapter_12_Ch12_Act1_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.SaekiTatsuya, character: "佐伯達也", dialogue: "每個欄位旁邊標來源。文件直接可見的，寫「文」。妳個人記得的，寫「記」。別人轉述給妳的，寫「述」。妳自己推的，寫「推」。", background: Background.Chapter_12_Ch12_Act1_S0, portrait: Portrait.SaekiTatsuya_Determined },
    { characterId: CharacterId.SaekiTatsuya, character: "佐伯達也", dialogue: "不要混。文件上有的和妳腦袋裡記的，分開寫。", background: Background.Chapter_12_Ch12_Act1_S0, portrait: Portrait.SaekiTatsuya_Determined },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯他在教我怎麼把記憶和證據分開。兩輪的東西混在我腦袋裡。他知道。他不知道有兩輪，但他知道我會把記得的東西當成文件上有的。", background: Background.Chapter_12_Ch12_Act1_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她點頭。拿起筆。在模板上方先寫了四個標記的縮寫。文。記。述。推。", background: Background.Chapter_12_Ch12_Act1_S0 },
    { characterId: CharacterId.SaekiTatsuya, character: "佐伯達也", dialogue: "先做刻痕。", background: Background.Chapter_12_Ch12_Act1_S0, portrait: Portrait.SaekiTatsuya_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他從電腦包裡拿出一個牛皮紙信封。從裡面抽出兩張影本。", background: Background.Chapter_12_Ch12_Act1_S0 },
    { characterId: CharacterId.SaekiTatsuya, character: "佐伯達也", dialogue: "A，妳弟弟的鏡子背面。B，藤川女兒的藥盒表面。兩份都是影本，不是原件。", background: Background.Chapter_12_Ch12_Act1_S0, portrait: Portrait.SaekiTatsuya_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他把兩張影本並排放在桌上。A在左，B在右。中間隔了大約十公分。", background: Background.Chapter_12_Ch12_Act1_S0 },
    { characterId: CharacterId.SaekiTatsuya, character: "佐伯達也", dialogue: "方向先固定。鏡子以鉸鏈方向為上。藥盒以開口方向為上。不旋轉。不翻面。不重排線條。", background: Background.Chapter_12_Ch12_Act1_S0, portrait: Portrait.SaekiTatsuya_Determined },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯他在定座標系。不是在看刻痕長什麼樣。是先固定看的方式。方向鎖死之後，看到的東西才有意義。", background: Background.Chapter_12_Ch12_Act1_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.SaekiTatsuya, character: "佐伯達也", dialogue: "現在，各自記。妳記妳的，我記我的。不要對照。不要討論。各自寫。", background: Background.Chapter_12_Ch12_Act1_S0, portrait: Portrait.SaekiTatsuya_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他遞給她一張白紙。自己也拿了一張。", background: Background.Chapter_12_Ch12_Act1_S0 },
    { characterId: CharacterId.SaekiTatsuya, character: "佐伯達也", dialogue: "記四項。可確認的短線數量。長斜線位置。有沒有封閉形狀。哪些筆畫可能只是磨損。", background: Background.Chapter_12_Ch12_Act1_S0, portrait: Portrait.SaekiTatsuya_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "澪低頭看A影本。那是她昨晚描圖的列印——在書桌前用透明描圖紙覆在鏡背上描的，今天帶的是影本。幾條短線。不規則。有些間距很近，像被擠在一起。有些分開。", background: Background.Chapter_12_Ch12_Act1_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯我昨晚描過一次。但那是原件。現在是影本。影本會丟細節。我記得原件上的東西，但我要記的是影本上看到的，不是我記得的。", background: Background.Chapter_12_Ch12_Act1_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她強迫自己只看影本。不看旁邊的描圖。不調動昨晚的記憶。", background: Background.Chapter_12_Ch12_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "短線。她數。一、二、三、四。四條可以確認的短線。第五條很模糊，可能是磨損。她寫「四條確認，一條疑似磨損」。", background: Background.Chapter_12_Ch12_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "長斜線。一條。從右上到左下。偏中間偏左。她寫下位置。", background: Background.Chapter_12_Ch12_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "封閉形狀。沒有。她寫「無封閉形狀」。", background: Background.Chapter_12_Ch12_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "可能只是磨損的筆畫。右下角有一小段不連續的痕跡。不像刻意刻的。她寫「右下角疑似磨損」。", background: Background.Chapter_12_Ch12_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她抬頭。佐伯還在寫。他的筆跡比她小。很工整。像在填報表。", background: Background.Chapter_12_Ch12_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他寫完A，翻到B。她也翻到B。", background: Background.Chapter_12_Ch12_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "B是美空的藥盒表面影本。藤川真理提供的。澪沒見過原件。她只看影本。", background: Background.Chapter_12_Ch12_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "短線比A多。她數了兩遍。六條確認。兩條疑似磨損。一條長斜線，從左上到右下。沒有封閉形狀。左側有一段不規則刮痕，可能是開蓋時磨到的。", background: Background.Chapter_12_Ch12_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她寫完。放下筆。", background: Background.Chapter_12_Ch12_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "佐伯也寫完了。他把兩張白紙並排看了一遍。沒有讓她看他的。", background: Background.Chapter_12_Ch12_Act1_S0 },
    { characterId: CharacterId.SaekiTatsuya, character: "佐伯達也", dialogue: "收起來。封存。等比完文件再打開。", background: Background.Chapter_12_Ch12_Act1_S0, portrait: Portrait.SaekiTatsuya_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他把兩人的記錄各自折好，放進同一個信封。封口。在正面寫上日期和「刻痕盲描 A/B」。", background: Background.Chapter_12_Ch12_Act1_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯為什麼要先描再比文件。因為如果我先看到 G07 之類的編號，再回頭看這些刮痕，我會自動把模糊的線拼成那個編號。他不是在保護證據。他是在保護我不騙自己。", background: Background.Chapter_12_Ch12_Act1_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "07:51。刻痕封存完畢。", background: Background.Chapter_12_Ch12_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "佐伯把信封收進電腦包。拉拉鏈。拉了兩次才拉上。", background: Background.Chapter_12_Ch12_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "然後他看著桌上那張澪昨晚填了一半的模板。", background: Background.Chapter_12_Ch12_Act1_S0 },
    { characterId: CharacterId.SaekiTatsuya, character: "佐伯達也", dialogue: "悠真的欄位。妳填了哪些？", background: Background.Chapter_12_Ch12_Act1_S0, portrait: Portrait.SaekiTatsuya_Determined },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "計畫名稱、招募入口、第二階段邀請、裝置名稱。其他空的。", background: Background.Chapter_12_Ch12_Act1_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.SaekiTatsuya, character: "佐伯達也", dialogue: "一個一個來。唸給我聽。我同時看妳帶來的列印。", background: Background.Chapter_12_Ch12_Act1_S0, portrait: Portrait.SaekiTatsuya_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "澪把模板拉到面前。旁邊放學校說明單的列印、預約頁截圖的列印。", background: Background.Chapter_12_Ch12_Act1_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "公開計畫名。關東青少年睡眠支援計畫。來源：學校說明單。標「文」。", background: Background.Chapter_12_Ch12_Act1_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.SaekiTatsuya, character: "佐伯達也", dialogue: "確認。說明單右上角有計畫全稱。", background: Background.Chapter_12_Ch12_Act1_S0, portrait: Portrait.SaekiTatsuya_Determined },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "招募入口。校內健康問卷。來源：學校通知。標「文」。", background: Background.Chapter_12_Ch12_Act1_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.SaekiTatsuya, character: "佐伯達也", dialogue: "確認。", background: Background.Chapter_12_Ch12_Act1_S0, portrait: Portrait.SaekiTatsuya_Determined },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "第二階段邀請。手機簡訊與紙本通知。來源：預約提醒。標「文」。", background: Background.Chapter_12_Ch12_Act1_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.SaekiTatsuya, character: "佐伯達也", dialogue: "簡訊妳還留著嗎？", background: Background.Chapter_12_Ch12_Act1_S0, portrait: Portrait.SaekiTatsuya_Determined },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "截圖。列印在這裡。", background: Background.Chapter_12_Ch12_Act1_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她翻到預約頁截圖的列印。佐伯拿過去看。看了幾秒。", background: Background.Chapter_12_Ch12_Act1_S0 },
    { characterId: CharacterId.SaekiTatsuya, character: "佐伯達也", dialogue: "裝置名稱。", background: Background.Chapter_12_Ch12_Act1_S0, portrait: Portrait.SaekiTatsuya_Determined },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "SleepCare Mini。來源：第二階段預約頁截圖。標「文」。", background: Background.Chapter_12_Ch12_Act1_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.SaekiTatsuya, character: "佐伯達也", dialogue: "確認。截圖中段有型號欄。", background: Background.Chapter_12_Ch12_Act1_S0, portrait: Portrait.SaekiTatsuya_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他翻到截圖下方。停了一下。", background: Background.Chapter_12_Ch12_Act1_S0 },
    { characterId: CharacterId.SaekiTatsuya, character: "佐伯達也", dialogue: "頁尾。", background: Background.Chapter_12_Ch12_Act1_S0, portrait: Portrait.SaekiTatsuya_Determined },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "這個我昨晚才注意到。之前只看了預約日期和裝置領取。頁尾有一行小字。前綴是 TKS。", background: Background.Chapter_12_Ch12_Act1_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.SaekiTatsuya, character: "佐伯達也", dialogue: "標「文」。來源：未裁切說明單與預約頁截圖。", background: Background.Chapter_12_Ch12_Act1_S0, portrait: Portrait.SaekiTatsuya_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他在自己的筆記上寫了什麼。澪看不到。", background: Background.Chapter_12_Ch12_Act1_S0 },
    { characterId: CharacterId.SaekiTatsuya, character: "佐伯達也", dialogue: "資料處理窗口。", background: Background.Chapter_12_Ch12_Act1_S0, portrait: Portrait.SaekiTatsuya_Determined },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "說明單背面的個資條款裡有。但我還沒跟其他文件比對。標「文」，備註「待比對」。", background: Background.Chapter_12_Ch12_Act1_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.SaekiTatsuya, character: "佐伯達也", dialogue: "可以。", background: Background.Chapter_12_Ch12_Act1_S0, portrait: Portrait.SaekiTatsuya_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "08:09。欄位填到一半。桌上多了兩杯水。服務生放的。佐伯沒碰。澪喝了一口。", background: Background.Chapter_12_Ch12_Act1_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "清晨異常。簡易結果畫面上有一段尖峰。6:10 到 6:15 之間。分鐘不精確。來源：簡易結果畫面截圖。標「文」。", background: Background.Chapter_12_Ch12_Act1_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.SaekiTatsuya, character: "佐伯達也", dialogue: "不能精確到分？", background: Background.Chapter_12_Ch12_Act1_S0, portrait: Portrait.SaekiTatsuya_Determined },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "不能。畫面只顯示五分鐘區間的柱狀圖。沒有分鐘刻度。", background: Background.Chapter_12_Ch12_Act1_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.SaekiTatsuya, character: "佐伯達也", dialogue: "記下來。6:10 至 6:15。不精確。", background: Background.Chapter_12_Ch12_Act1_S0, portrait: Portrait.SaekiTatsuya_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "08:17。剩最後一欄。", background: Background.Chapter_12_Ch12_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "管理碼。", background: Background.Chapter_12_Ch12_Act1_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯管理碼。這一欄昨晚填模板的時候我看到了。預約頁截圖的最下方。很小。小到第一次看的時候完全跳過了。", background: Background.Chapter_12_Ch12_Act1_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她翻到截圖列印。最下方。一行小字。", background: Background.Chapter_12_Ch12_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "G07／12。", background: Background.Chapter_12_Ch12_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "四個字元。一個斜線。", background: Background.Chapter_12_Ch12_Act1_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯G07。斜線。12。", background: Background.Chapter_12_Ch12_Act1_S0, portrait: Portrait.AsakuraMio_Shocked },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她看著那行字。手指停在紙上。", background: Background.Chapter_12_Ch12_Act1_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯悠真。你在預約頁上有一個編號。G07。斜線。12。你被放進一個群組。群組裡至少有十二個。你是第十二個。或者只是編號十二。我不知道。但你在那裡。你在一份我以前沒看完的文件裡，被寫成四個字元。", background: Background.Chapter_12_Ch12_Act1_S0, portrait: Portrait.AsakuraMio_Shocked },
    { characterId: CharacterId.SaekiTatsuya, character: "佐伯達也", dialogue: "管理碼。G07／12。來源：第二階段預約頁截圖下方小字。標「文」。", background: Background.Chapter_12_Ch12_Act1_S0, portrait: Portrait.SaekiTatsuya_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他的聲音很平。像在念欄位名稱。", background: Background.Chapter_12_Ch12_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他在自己的筆記上，G07／12 旁邊寫了三個字。", background: Background.Chapter_12_Ch12_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "意義未明。", background: Background.Chapter_12_Ch12_Act1_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯意義未明。他寫的是意義未明。不是「悠真的編號」。不是「第十二名受試者」。是意義未明。因為他不知道這是什麼。他知道這是一串出現在文件上的字元。他不知道它代表什麼。", background: Background.Chapter_12_Ch12_Act1_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "澪拿起私人筆記。翻到那一頁。她在 G07／12 旁邊寫了一個詞。", background: Background.Chapter_12_Ch12_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "悠真。", background: Background.Chapter_12_Ch12_Act1_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯佐伯寫意義未明。我寫悠真。他寫的是文件能支持的結論。我寫的是文件不能支持的東西。但我不想讓你只剩一個編號。G07／12。那不是你。你是悠真。你會把青椒挑到我碗裡。你會在遊戲裡用奇怪的名字開帳號。你會把交通卡借給同學騙他們一天。你不是 G07 斜線 12。", background: Background.Chapter_12_Ch12_Act1_S0, portrait: Portrait.AsakuraMio_Sad },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她把私人筆記合上。放進背包側袋。", background: Background.Chapter_12_Ch12_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "佐伯沒有看到她寫了什麼。", background: Background.Chapter_12_Ch12_Act1_S0 },
    { characterId: CharacterId.SaekiTatsuya, character: "佐伯達也", dialogue: "欄位填完了？", background: Background.Chapter_12_Ch12_Act1_S0, portrait: Portrait.SaekiTatsuya_Determined },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "填完了。", background: Background.Chapter_12_Ch12_Act1_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.SaekiTatsuya, character: "佐伯達也", dialogue: "來源標記呢？", background: Background.Chapter_12_Ch12_Act1_S0, portrait: Portrait.SaekiTatsuya_Determined },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "全標了。大部分是「文」。沒有「記」。", background: Background.Chapter_12_Ch12_Act1_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.SaekiTatsuya, character: "佐伯達也", dialogue: "好。沒有「記」就對了。今天只看文件上有的。", background: Background.Chapter_12_Ch12_Act1_S0, portrait: Portrait.SaekiTatsuya_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "08:31。他把模板和列印收攏。沒有裝進自己的包。推到澪那一側。", background: Background.Chapter_12_Ch12_Act1_S0 },
    { characterId: CharacterId.SaekiTatsuya, character: "佐伯達也", dialogue: "這些是妳弟弟的。妳收。九點區民館開門。帶過去。", background: Background.Chapter_12_Ch12_Act1_S0, portrait: Portrait.SaekiTatsuya_Determined },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯他把文件推回來。不收走。這是悠真的資料。不是其他家庭的。我可以帶。", background: Background.Chapter_12_Ch12_Act1_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.SaekiTatsuya, character: "佐伯達也", dialogue: "九點見。", background: Background.Chapter_12_Ch12_Act1_S0, portrait: Portrait.SaekiTatsuya_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他站起來。拿起電腦包。拉鏈這次一次就拉上了。", background: Background.Chapter_12_Ch12_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他走到門口。推門出去。沒有回頭。", background: Background.Chapter_12_Ch12_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "08:34。澪一個人坐在窗邊。", background: Background.Chapter_12_Ch12_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "桌上是悠真的欄位表。八個欄位。八個來源標記。最下面一行寫著 G07／12。", background: Background.Chapter_12_Ch12_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她看著那行字。看了很久。", background: Background.Chapter_12_Ch12_Act1_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯G07／12。悠真。這是文件上有的。這是我知道的。文件上有一個編號。我知道那是我弟弟。兩件事。分開寫。一邊是文。一邊是記。佐伯要我分開。我分開了。但分開之後，兩邊都更冷了。", background: Background.Chapter_12_Ch12_Act1_S0, portrait: Portrait.AsakuraMio_Sad },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "08:40。她把所有紙本收進背包。拉上拉鏈。站起來。", background: Background.Chapter_12_Ch12_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "區民館九點開門。她還有二十分鐘的路。", background: Background.Chapter_12_Ch12_Act1_S0 },
];
